import React from 'react';
import { Fade } from 'react-slideshow-image';
import 'react-slideshow-image/dist/styles.css'

const Banner = () => {


const fadeImages = [
  {
    url: 'https://www.gadgetvoize.com/wp-content/uploads/2022/02/Amazon-Header-Banner.jpg',
 
  },
  {
    url: 'https://www.zionandzion.com/wordpress/wp-content/uploads/2022/10/2022_09_How-to-Properly-Use-Marketing-Automation-in-the-Home-Service-HVAC-Industry_1200x675.jpg',

  },
  {
    url: '',

  },
];

    return (
      <div className="">
        <Fade>
          {fadeImages.map((fadeImage, index) => (
            <div key={index}> 
              {/* <img style={{ height:'50%'}} src={fadeImage.url} /> */}
              <img class="object-fill h-48 w-96 ..." src={fadeImage.url} />
              {/* <h2>{fadeImage.caption}</h2> */}
            </div>
          ))}
        </Fade>
      </div>
    )
  }

export default Banner
